33	  localparam AES_128_BIT_KEY = 1'h0;
34	  localparam AES_256_BIT_KEY = 1'h1;
35	
36	  localparam AES128_ROUNDS = 4'ha;
37	  localparam AES256_ROUNDS = 4'he;
38	
39	  localparam NO_UPDATE    = 3'h0;
40	  localparam INIT_UPDATE  = 3'h1;
41	  localparam SBOX_UPDATE  = 3'h2;
42	  localparam MAIN_UPDATE  = 3'h3;
43	  localparam FINAL_UPDATE = 3'h4;
44	
45	  localparam CTRL_IDLE  = 3'h0;
46	  localparam CTRL_INIT  = 3'h1;
47	  localparam CTRL_SBOX  = 3'h2;
48	  localparam CTRL_MAIN  = 3'h3;
49	  localparam CTRL_FINAL = 3'h4;
50	
51	
52	  //----------------------------------------------------------------
53	  // Round functions with sub functions.
54	  //----------------------------------------------------------------
55	  function [7 : 0] gm2(input [7 : 0] op);
56	    begin
57	      gm2 = {op[6 : 0], 1'b0} ^ (8'h1b & {8{op[7]}});
58	    end
59	  endfunction // gm2
60	
61	  function [7 : 0] gm3(input [7 : 0] op);
62	    begin
63	      gm3 = gm2(op) ^ op;
64	    end
65	  endfunction // gm3
66	
67	  function [31 : 0] mixw(input [31 : 0] w);
68	    reg [7 : 0] b0, b1, b2, b3;
69	    reg [7 : 0] mb0, mb1, mb2, mb3;
70	    begin
71	      b0 = w[31 : 24];
72	      b1 = w[23 : 16];
73	      b2 = w[15 : 08];
74	      b3 = w[07 : 00];
75	
76	      mb0 = gm2(b0) ^ gm3(b1) ^ b2      ^ b3;
77	      mb1 = b0      ^ gm2(b1) ^ gm3(b2) ^ b3;
78	      mb2 = b0      ^ b1      ^ gm2(b2) ^ gm3(b3);
79	      mb3 = gm3(b0) ^ b1      ^ b2      ^ gm2(b3);
80	
81	      mixw = {mb0, mb1, mb2, mb3};
82	    end
83	  endfunction // mixw
84	
85	  function [127 : 0] mixcolumns(input [127 : 0] data);
86	    reg [31 : 0] w0, w1, w2, w3;
87	    reg [31 : 0] ws0, ws1, ws2, ws3;
88	    begin
89	      w0 = data[127 : 096];
90	      w1 = data[095 : 064];
91	      w2 = data[063 : 032];
92	      w3 = data[031 : 000];
93	
94	      ws0 = mixw(w0);
95	      ws1 = mixw(w1);
96	      ws2 = mixw(w2);
97	      ws3 = mixw(w3);
98	
99	      mixcolumns = {ws0, ws1, ws2, ws3};
100	    end
101	  endfunction // mixcolumns
102	
103	  function [127 : 0] shiftrows(input [127 : 0] data);
104	    reg [31 : 0] w0, w1, w2, w3;
105	    reg [31 : 0] ws0, ws1, ws2, ws3;
106	    begin
107	      w0 = data[127 : 096];
108	      w1 = data[095 : 064];
109	      w2 = data[063 : 032];
110	      w3 = data[031 : 000];
111	
112	      ws0 = {w0[31 : 24], w1[23 : 16], w2[15 : 08], w3[07 : 00]};
113	      ws1 = {w1[31 : 24], w2[23 : 16], w3[15 : 08], w0[07 : 00]};
114	      ws2 = {w2[31 : 24], w3[23 : 16], w0[15 : 08], w1[07 : 00]};
115	      ws3 = {w3[31 : 24], w0[23 : 16], w1[15 : 08], w2[07 : 00]};
116	
117	      shiftrows = {ws0, ws1, ws2, ws3};
118	    end
119	  endfunction // shiftrows
120	
121	  function [127 : 0] addroundkey(input [127 : 0] data, input [127 : 0] rkey);
122	    begin
123	      addroundkey = data ^ rkey;
124	    end
125	  endfunction // addroundkey
126	
127	
128	  //----------------------------------------------------------------
129	  // Registers including update variables and write enable.
130	  //----------------------------------------------------------------
131	  reg [1 : 0]   sword_ctr_reg;
132	  reg [1 : 0]   sword_ctr_new;
133	  reg           sword_ctr_we;
134	  reg           sword_ctr_inc;
135	  reg           sword_ctr_rst;
136	
137	  reg [3 : 0]   round_ctr_reg;
138	  reg [3 : 0]   round_ctr_new;
139	  reg           round_ctr_we;
140	  reg           round_ctr_rst;
141	  reg           round_ctr_inc;
142	
143	  reg [127 : 0] block_new;
144	  reg [31 : 0]  block_w0_reg;
145	  reg [31 : 0]  block_w1_reg;
146	  reg [31 : 0]  block_w2_reg;
147	  reg [31 : 0]  block_w3_reg;
148	  reg           block_w0_we;
149	  reg           block_w1_we;
150	  reg           block_w2_we;
151	  reg           block_w3_we;
152	
153	  reg           ready_reg;
154	  reg           ready_new;
155	  reg           ready_we;
156	
157	  reg [2 : 0]   enc_ctrl_reg;
158	  reg [2 : 0]   enc_ctrl_new;
159	  reg           enc_ctrl_we;
160	
161	
162	  //----------------------------------------------------------------
163	  // Wires.
164	  //----------------------------------------------------------------
165	  reg [2 : 0]  update_type;
166	  reg [31 : 0] muxed_sboxw;
167	
168	
169	  //----------------------------------------------------------------
170	  // Concurrent connectivity for ports etc.
171	  //----------------------------------------------------------------
172	  assign round     = round_ctr_reg;
173	  assign sboxw     = muxed_sboxw;
174	  assign new_block = {block_w0_reg, block_w1_reg, block_w2_reg, block_w3_reg};
175	  assign ready     = ready_reg;
176	
177	
178	  //----------------------------------------------------------------
179	  // reg_update
180	  //
181	  // Update functionality for all registers in the core.
182	  // All registers are positive edge triggered with asynchronous
183	  // active low reset. All registers have write enable.
184	  //----------------------------------------------------------------
185	  always @ (posedge clk or negedge reset_n)
186	    begin: reg_update
187	      if (!reset_n)
188	        begin
189	          block_w0_reg  <= 32'h0;
190	          block_w1_reg  <= 32'h0;
191	          block_w2_reg  <= 32'h0;
192	          block_w3_reg  <= 32'h0;
193	          sword_ctr_reg <= 2'h0;
194	          round_ctr_reg <= 4'h0;
195	          ready_reg     <= 1'b1;
196	          enc_ctrl_reg  <= CTRL_IDLE;
197	        end
198	      else
199	        begin
200	          if (block_w0_we)
201	            block_w0_reg <= block_new[127 : 096];
202	
203	          if (block_w1_we)
204	            block_w1_reg <= block_new[095 : 064];
205	
206	          if (block_w2_we)
207	            block_w2_reg <= block_new[063 : 032];
208	
209	          if (block_w3_we)
210	            block_w3_reg <= block_new[031 : 000];
211	
212	          if (sword_ctr_we)
213	            sword_ctr_reg <= sword_ctr_new;
214	
215	          if (round_ctr_we)
216	            round_ctr_reg <= round_ctr_new;
217	
218	          if (ready_we)
219	            ready_reg <= ready_new;
220	
221	          if (enc_ctrl_we)
222	            enc_ctrl_reg <= enc_ctrl_new;
223	        end
224	    end // reg_update
225	
226	
227	  //----------------------------------------------------------------
228	  // round_logic
229	  //
230	  // The logic needed to implement init, main and final rounds.
231	  //----------------------------------------------------------------
232	  always @*
233	    begin : round_logic
234	      reg [127 : 0] old_block, shiftrows_block, mixcolumns_block;
235	      reg [127 : 0] addkey_init_block, addkey_main_block, addkey_final_block;
236	
237	      block_new   = 128'h0;
238	      muxed_sboxw = 32'h0;
239	      block_w0_we = 1'b0;
240	      block_w1_we = 1'b0;
241	      block_w2_we = 1'b0;
242	      block_w3_we = 1'b0;
243	
244	      old_block          = {block_w0_reg, block_w1_reg, block_w2_reg, block_w3_reg};
245	      shiftrows_block    = shiftrows(old_block);
246	      mixcolumns_block   = mixcolumns(shiftrows_block);
247	      addkey_init_block  = addroundkey(block, round_key);
248	      addkey_main_block  = addroundkey(mixcolumns_block, round_key);
249	      addkey_final_block = addroundkey(shiftrows_block, round_key);
250	
251	      case (update_type)
252	        INIT_UPDATE:
253	          begin
254	            block_new    = addkey_init_block;
255	            block_w0_we  = 1'b1;
256	            block_w1_we  = 1'b1;
257	            block_w2_we  = 1'b1;
258	            block_w3_we  = 1'b1;
259	          end
260	
261	        SBOX_UPDATE:
262	          begin
263	            block_new = {new_sboxw, new_sboxw, new_sboxw, new_sboxw};
264	
265	            case (sword_ctr_reg)
266	              2'h0:
267	                begin
268	                  muxed_sboxw = block_w0_reg;
269	                  block_w0_we = 1'b1;
270	                end
271	
272	              2'h1:
273	                begin
274	                  muxed_sboxw = block_w1_reg;
275	                  block_w1_we = 1'b1;
276	                end
277	
278	              2'h2:
279	                begin
280	                  muxed_sboxw = block_w2_reg;
281	                  block_w2_we = 1'b1;
282	                end
283	
284	              2'h3:
285	                begin
286	                  muxed_sboxw = block_w3_reg;
287	                  block_w3_we = 1'b1;
288	                end
289	            endcase // case (sbox_mux_ctrl_reg)
290	          end
291	
292	        MAIN_UPDATE:
293	          begin
294	            block_new    = addkey_main_block;
295	            block_w0_we  = 1'b1;
296	            block_w1_we  = 1'b1;
297	            block_w2_we  = 1'b1;
298	            block_w3_we  = 1'b1;
299	          end
300	
301	        FINAL_UPDATE:
302	          begin
303	            block_new    = addkey_final_block;
304	            block_w0_we  = 1'b1;
305	            block_w1_we  = 1'b1;
306	            block_w2_we  = 1'b1;
307	            block_w3_we  = 1'b1;
308	          end
309	
310	        default:
311	          begin
312	          end
313	      endcase // case (update_type)
314	    end // round_logic
315	
316	
317	  //----------------------------------------------------------------
318	  // sword_ctr
319	  //
320	  // The subbytes word counter with reset and increase logic.
321	  //----------------------------------------------------------------
322	  always @*
323	    begin : sword_ctr
324	      sword_ctr_new = 2'h0;
325	      sword_ctr_we  = 1'b0;
326	
327	      if (sword_ctr_rst)
328	        begin
329	          sword_ctr_new = 2'h0;
330	          sword_ctr_we  = 1'b1;
331	        end
332	      else if (sword_ctr_inc)
333	        begin
334	          sword_ctr_new = sword_ctr_reg + 1'b1;
335	          sword_ctr_we  = 1'b1;
336	        end
337	    end // sword_ctr
338	
339	
340	  //----------------------------------------------------------------
341	  // round_ctr
342	  //
343	  // The round counter with reset and increase logic.
344	  //----------------------------------------------------------------
345	  always @*
346	    begin : round_ctr
347	      round_ctr_new = 4'h0;
348	      round_ctr_we  = 1'b0;
349	
350	      if (round_ctr_rst)
351	        begin
352	          round_ctr_new = 4'h0;
353	          round_ctr_we  = 1'b1;
354	        end
355	      else if (round_ctr_inc)
356	        begin
357	          round_ctr_new = round_ctr_reg + 1'b1;
358	          round_ctr_we  = 1'b1;
359	        end
360	    end // round_ctr
361	
362	
363	  //----------------------------------------------------------------
364	  // encipher_ctrl
365	  //
366	  // The FSM that controls the encipher operations.
367	  //----------------------------------------------------------------
368	  always @*
369	    begin: encipher_ctrl
370	      reg [3 : 0] num_rounds;
371	
372	      // Default assignments.
373	      sword_ctr_inc = 1'b0;
374	      sword_ctr_rst = 1'b0;
375	      round_ctr_inc = 1'b0;
376	      round_ctr_rst = 1'b0;
377	      ready_new     = 1'b0;
378	      ready_we      = 1'b0;
379	      update_type   = NO_UPDATE;
380	      enc_ctrl_new  = CTRL_IDLE;
381	      enc_ctrl_we   = 1'b0;
382	
383	      if (keylen == AES_256_BIT_KEY)
384	        begin
385	          num_rounds = AES256_ROUNDS;
386	        end
387	      else
388	        begin
389	          num_rounds = AES128_ROUNDS;
390	        end
391	
392	      case(enc_ctrl_reg)
393	        CTRL_IDLE:
394	          begin
395	            if (next)
396	              begin
397	                round_ctr_rst = 1'b1;
398	                ready_new     = 1'b0;
399	                ready_we      = 1'b1;
400	                enc_ctrl_new  = CTRL_INIT;
401	                enc_ctrl_we   = 1'b1;
402	              end
403	          end
404	
405	        CTRL_INIT:
406	          begin
407	            round_ctr_inc = 1'b1;
408	            sword_ctr_rst = 1'b1;
409	            update_type   = INIT_UPDATE;
410	            enc_ctrl_new  = CTRL_SBOX;
411	            enc_ctrl_we   = 1'b1;
412	          end
413	
414	        CTRL_SBOX:
415	          begin
416	            sword_ctr_inc = 1'b1;
417	            update_type   = SBOX_UPDATE;
418	            if (sword_ctr_reg == 2'h3)
419	              begin
420	                enc_ctrl_new  = CTRL_MAIN;
421	                enc_ctrl_we   = 1'b1;
422	              end
423	          end
424	
425	        CTRL_MAIN:
426	          begin
427	            sword_ctr_rst = 1'b1;
428	            round_ctr_inc = 1'b1;
429	            if (round_ctr_reg < num_rounds)
430	              begin
431	                update_type   = MAIN_UPDATE;
432	                enc_ctrl_new  = CTRL_SBOX;
433	                enc_ctrl_we   = 1'b1;
434	              end
435	            else
436	              begin
437	                update_type  = FINAL_UPDATE;
438	                ready_new    = 1'b1;
439	                ready_we     = 1'b1;
440	                enc_ctrl_new = CTRL_IDLE;
441	                enc_ctrl_we  = 1'b1;
442	              end
443	          end
444	
445	        default:
446	          begin
447	            // Empty. Just here to make the synthesis tool happy.
448	          end
449	      endcase // case (enc_ctrl_reg)
450	    end // encipher_ctrl
451	
452	endmodule // aes_encipher_block
453	
