1	//======================================================================
2	//
3	// aes_decipher_block.v
4	// --------------------
5	// The AES decipher round. A pure combinational module that implements
6	// the initial round, main round and final round logic for
7	// decciper operations.
8	//
9	//======================================================================
10	module aes_decipher_block(
11	                          input wire            clk,
12	                          input wire            reset_n,
13	
14	                          input wire            next,
15	
16	                          input wire            keylen,
17	                          output wire [3 : 0]   round,
18	                          input wire [127 : 0]  round_key,
19	
20	                          input wire [127 : 0]  block,
21	                          output wire [127 : 0] new_block,
22	                          output wire           ready
23	                         );
24	
25	
26	  //----------------------------------------------------------------
27	  // Internal constant and parameter definitions.
28	  //----------------------------------------------------------------
29	  localparam AES_128_BIT_KEY = 1'h0;
30	  localparam AES_256_BIT_KEY = 1'h1;
31	
32	  localparam AES128_ROUNDS = 4'ha;
33	  localparam AES256_ROUNDS = 4'he;
34	
35	  localparam NO_UPDATE    = 3'h0;
36	  localparam INIT_UPDATE  = 3'h1;
37	  localparam SBOX_UPDATE  = 3'h2;
38	  localparam MAIN_UPDATE  = 3'h3;
39	  localparam FINAL_UPDATE = 3'h4;
40	
41	  localparam CTRL_IDLE  = 3'h0;
42	  localparam CTRL_INIT  = 3'h1;
43	  localparam CTRL_SBOX  = 3'h2;
44	  localparam CTRL_MAIN  = 3'h3;
45	  localparam CTRL_FINAL = 3'h4;
46	
47	
48	  //----------------------------------------------------------------
49	  // Gaolis multiplication functions for Inverse MixColumn.
50	  //----------------------------------------------------------------
51	  function [7 : 0] gm2(input [7 : 0] op);
52	    begin
53	      gm2 = {op[6 : 0], 1'b0} ^ (8'h1b & {8{op[7]}});
54	    end
55	  endfunction // gm2
56	
57	  function [7 : 0] gm3(input [7 : 0] op);
58	    begin
59	      gm3 = gm2(op) ^ op;
60	    end
61	  endfunction // gm3
62	
63	  function [7 : 0] gm4(input [7 : 0] op);
64	    begin
65	      gm4 = gm2(gm2(op));
66	    end
67	  endfunction // gm4
68	
69	  function [7 : 0] gm8(input [7 : 0] op);
70	    begin
71	      gm8 = gm2(gm4(op));
72	    end
73	  endfunction // gm8
74	
75	  function [7 : 0] gm09(input [7 : 0] op);
76	    begin
77	      gm09 = gm8(op) ^ op;
78	    end
79	  endfunction // gm09
80	
81	  function [7 : 0] gm11(input [7 : 0] op);
82	    begin
83	      gm11 = gm8(op) ^ gm2(op) ^ op;
84	    end
85	  endfunction // gm11
86	
87	  function [7 : 0] gm13(input [7 : 0] op);
88	    begin
89	      gm13 = gm8(op) ^ gm4(op) ^ op;
90	    end
91	  endfunction // gm13
92	
93	  function [7 : 0] gm14(input [7 : 0] op);
94	    begin
95	      gm14 = gm8(op) ^ gm4(op) ^ gm2(op);
96	    end
97	  endfunction // gm14
98	
99	  function [31 : 0] inv_mixw(input [31 : 0] w);
100	    reg [7 : 0] b0, b1, b2, b3;
101	    reg [7 : 0] mb0, mb1, mb2, mb3;
102	    begin
103	      b0 = w[31 : 24];
104	      b1 = w[23 : 16];
105	      b2 = w[15 : 08];
106	      b3 = w[07 : 00];
107	
108	      mb0 = gm14(b0) ^ gm11(b1) ^ gm13(b2) ^ gm09(b3);
109	      mb1 = gm09(b0) ^ gm14(b1) ^ gm11(b2) ^ gm13(b3);
110	      mb2 = gm13(b0) ^ gm09(b1) ^ gm14(b2) ^ gm11(b3);
111	      mb3 = gm11(b0) ^ gm13(b1) ^ gm09(b2) ^ gm14(b3);
112	
113	      inv_mixw = {mb0, mb1, mb2, mb3};
114	    end
115	  endfunction // mixw
116	
117	  function [127 : 0] inv_mixcolumns(input [127 : 0] data);
118	    reg [31 : 0] w0, w1, w2, w3;
119	    reg [31 : 0] ws0, ws1, ws2, ws3;
120	    begin
121	      w0 = data[127 : 096];
122	      w1 = data[095 : 064];
123	      w2 = data[063 : 032];
124	      w3 = data[031 : 000];
125	
126	      ws0 = inv_mixw(w0);
127	      ws1 = inv_mixw(w1);
128	      ws2 = inv_mixw(w2);
129	      ws3 = inv_mixw(w3);
130	
131	      inv_mixcolumns = {ws0, ws1, ws2, ws3};
132	    end
133	  endfunction // inv_mixcolumns
134	
135	  function [127 : 0] inv_shiftrows(input [127 : 0] data);
136	    reg [31 : 0] w0, w1, w2, w3;
137	    reg [31 : 0] ws0, ws1, ws2, ws3;
138	    begin
139	      w0 = data[127 : 096];
140	      w1 = data[095 : 064];
141	      w2 = data[063 : 032];
142	      w3 = data[031 : 000];
143	
144	      ws0 = {w0[31 : 24], w3[23 : 16], w2[15 : 08], w1[07 : 00]};
145	      ws1 = {w1[31 : 24], w0[23 : 16], w3[15 : 08], w2[07 : 00]};
146	      ws2 = {w2[31 : 24], w1[23 : 16], w0[15 : 08], w3[07 : 00]};
147	      ws3 = {w3[31 : 24], w2[23 : 16], w1[15 : 08], w0[07 : 00]};
148	
149	      inv_shiftrows = {ws0, ws1, ws2, ws3};
150	    end
151	  endfunction // inv_shiftrows
152	
153	  function [127 : 0] addroundkey(input [127 : 0] data, input [127 : 0] rkey);
154	    begin
155	      addroundkey = data ^ rkey;
156	    end
157	  endfunction // addroundkey
158	
159	
160	  //----------------------------------------------------------------
161	  // Registers including update variables and write enable.
162	  //----------------------------------------------------------------
163	  reg [1 : 0]   sword_ctr_reg;
164	  reg [1 : 0]   sword_ctr_new;
165	  reg           sword_ctr_we;
166	  reg           sword_ctr_inc;
167	  reg           sword_ctr_rst;
168	
169	  reg [3 : 0]   round_ctr_reg;
170	  reg [3 : 0]   round_ctr_new;
171	  reg           round_ctr_we;
172	  reg           round_ctr_set;
173	  reg           round_ctr_dec;
174	
175	  reg [127 : 0] block_new;
176	  reg [31 : 0]  block_w0_reg;
177	  reg [31 : 0]  block_w1_reg;
178	  reg [31 : 0]  block_w2_reg;
179	  reg [31 : 0]  block_w3_reg;
180	  reg           block_w0_we;
181	  reg           block_w1_we;
182	  reg           block_w2_we;
183	  reg           block_w3_we;
184	
185	  reg           ready_reg;
186	  reg           ready_new;
187	  reg           ready_we;
188	
189	  reg [2 : 0]   dec_ctrl_reg;
190	  reg [2 : 0]   dec_ctrl_new;
191	  reg           dec_ctrl_we;
192	
193	
194	  //----------------------------------------------------------------
195	  // Wires.
196	  //----------------------------------------------------------------
197	  reg [31 : 0]  tmp_sboxw;
198	  wire [31 : 0] new_sboxw;
199	  reg [2 : 0]   update_type;
200	
201	
202	  //----------------------------------------------------------------
203	  // Instantiations.
204	  //----------------------------------------------------------------
205	  aes_inv_sbox inv_sbox_inst(.sword(tmp_sboxw), .new_sword(new_sboxw));
206	
207	
208	  //----------------------------------------------------------------
209	  // Concurrent connectivity for ports etc.
210	  //----------------------------------------------------------------
211	  assign round     = round_ctr_reg;
212	  assign new_block = {block_w0_reg, block_w1_reg, block_w2_reg, block_w3_reg};
213	  assign ready     = ready_reg;
214	
215	
216	  //----------------------------------------------------------------
217	  // reg_update
218	  //
219	  // Update functionality for all registers in the core.
220	  // All registers are positive edge triggered with synchronous
221	  // active low reset. All registers have write enable.
222	  //----------------------------------------------------------------
223	  always @ (posedge clk or negedge reset_n)
224	    begin: reg_update
225	      if (!reset_n)
226	        begin
227	          block_w0_reg  <= 32'h0;
228	          block_w1_reg  <= 32'h0;
229	          block_w2_reg  <= 32'h0;
230	          block_w3_reg  <= 32'h0;
231	          sword_ctr_reg <= 2'h0;
232	          round_ctr_reg <= 4'h0;
233	          ready_reg     <= 1'b1;
234	          dec_ctrl_reg  <= CTRL_IDLE;
235	        end
236	      else
237	        begin
238	          if (block_w0_we)
239	            block_w0_reg <= block_new[127 : 096];
240	
241	          if (block_w1_we)
242	            block_w1_reg <= block_new[095 : 064];
243	
244	          if (block_w2_we)
245	            block_w2_reg <= block_new[063 : 032];
246	
247	          if (block_w3_we)
248	            block_w3_reg <= block_new[031 : 000];
249	
250	          if (sword_ctr_we)
251	            sword_ctr_reg <= sword_ctr_new;
252	
253	          if (round_ctr_we)
254	            round_ctr_reg <= round_ctr_new;
255	
256	          if (ready_we)
257	            ready_reg <= ready_new;
258	
259	          if (dec_ctrl_we)
260	            dec_ctrl_reg <= dec_ctrl_new;
261	        end
262	    end // reg_update
263	
264	
265	  //----------------------------------------------------------------
266	  // round_logic
267	  //
268	  // The logic needed to implement init, main and final rounds.
269	  //----------------------------------------------------------------
270	  always @*
271	    begin : round_logic
272	      reg [127 : 0] old_block, inv_shiftrows_block, inv_mixcolumns_block;
273	      reg [127 : 0] addkey_block;
274	
275	      inv_shiftrows_block  = 128'h0;
276	      inv_mixcolumns_block = 128'h0;
277	      addkey_block         = 128'h0;
278	      block_new            = 128'h0;
279	      tmp_sboxw            = 32'h0;
280	      block_w0_we          = 1'b0;
281	      block_w1_we          = 1'b0;
282	      block_w2_we          = 1'b0;
283	      block_w3_we          = 1'b0;
284	
285	      old_block            = {block_w0_reg, block_w1_reg, block_w2_reg, block_w3_reg};
286	
287	      // Update based on update type.
288	      case (update_type)
289	        // InitRound
290	        INIT_UPDATE:
291	          begin
292	            old_block           = block;
293	            addkey_block        = addroundkey(old_block, round_key);
294	            inv_shiftrows_block = inv_shiftrows(addkey_block);
295	            block_new           = inv_shiftrows_block;
296	            block_w0_we         = 1'b1;
297	            block_w1_we         = 1'b1;
298	            block_w2_we         = 1'b1;
299	            block_w3_we         = 1'b1;
300	          end
301	
302	        SBOX_UPDATE:
303	          begin
304	            block_new = {new_sboxw, new_sboxw, new_sboxw, new_sboxw};
305	
306	            case (sword_ctr_reg)
307	              2'h0:
308	                begin
309	                  tmp_sboxw   = block_w0_reg;
310	                  block_w0_we = 1'b1;
311	                end
312	
313	              2'h1:
314	                begin
315	                  tmp_sboxw   = block_w1_reg;
316	                  block_w1_we = 1'b1;
317	                end
318	
319	              2'h2:
320	                begin
321	                  tmp_sboxw   = block_w2_reg;
322	                  block_w2_we = 1'b1;
323	                end
324	
325	              2'h3:
326	                begin
327	                  tmp_sboxw   = block_w3_reg;
328	                  block_w3_we = 1'b1;
329	                end
330	            endcase // case (sbox_mux_ctrl_reg)
331	          end
332	
333	        MAIN_UPDATE:
334	          begin
335	            addkey_block         = addroundkey(old_block, round_key);
336	            inv_mixcolumns_block = inv_mixcolumns(addkey_block);
337	            inv_shiftrows_block  = inv_shiftrows(inv_mixcolumns_block);
338	            block_new            = inv_shiftrows_block;
339	            block_w0_we          = 1'b1;
340	            block_w1_we          = 1'b1;
341	            block_w2_we          = 1'b1;
342	            block_w3_we          = 1'b1;
343	          end
344	
345	        FINAL_UPDATE:
346	          begin
347	            block_new    = addroundkey(old_block, round_key);
348	            block_w0_we  = 1'b1;
349	            block_w1_we  = 1'b1;
350	            block_w2_we  = 1'b1;
351	            block_w3_we  = 1'b1;
352	          end
353	
354	        default:
355	          begin
356	          end
357	      endcase // case (update_type)
358	    end // round_logic
359	
360	
361	  //----------------------------------------------------------------
362	  // sword_ctr
363	  //
364	  // The subbytes word counter with reset and increase logic.
365	  //----------------------------------------------------------------
366	  always @*
367	    begin : sword_ctr
368	      sword_ctr_new = 2'h0;
369	      sword_ctr_we  = 1'b0;
370	
371	      if (sword_ctr_rst)
372	        begin
373	          sword_ctr_new = 2'h0;
374	          sword_ctr_we  = 1'b1;
375	        end
376	      else if (sword_ctr_inc)
377	        begin
378	          sword_ctr_new = sword_ctr_reg + 1'b1;
379	          sword_ctr_we  = 1'b1;
380	        end
381	    end // sword_ctr
382	
383	
384	  //----------------------------------------------------------------
385	  // round_ctr
386	  //
387	  // The round counter with reset and increase logic.
388	  //----------------------------------------------------------------
389	  always @*
390	    begin : round_ctr
391	      round_ctr_new = 4'h0;
392	      round_ctr_we  = 1'b0;
393	
394	      if (round_ctr_set)
395	        begin
396	          if (keylen == AES_256_BIT_KEY)
397	            begin
398	              round_ctr_new = AES256_ROUNDS;
399	            end
400	          else
401	            begin
402	              round_ctr_new = AES128_ROUNDS;
403	            end
404	          round_ctr_we  = 1'b1;
405	        end
406	      else if (round_ctr_dec)
407	        begin
408	          round_ctr_new = round_ctr_reg - 1'b1;
409	          round_ctr_we  = 1'b1;
410	        end
411	    end // round_ctr
412	
413	
414	  //----------------------------------------------------------------
415	  // decipher_ctrl
416	  //
417	  // The FSM that controls the decipher operations.
418	  //----------------------------------------------------------------
419	  always @*
420	    begin: decipher_ctrl
421	      sword_ctr_inc = 1'b0;
422	      sword_ctr_rst = 1'b0;
423	      round_ctr_dec = 1'b0;
424	      round_ctr_set = 1'b0;
425	      ready_new     = 1'b0;
426	      ready_we      = 1'b0;
427	      update_type   = NO_UPDATE;
428	      dec_ctrl_new  = CTRL_IDLE;
429	      dec_ctrl_we   = 1'b0;
430	
431	      case(dec_ctrl_reg)
432	        CTRL_IDLE:
433	          begin
434	            if (next)
435	              begin
436	                round_ctr_set = 1'b1;
437	                ready_new     = 1'b0;
438	                ready_we      = 1'b1;
439	                dec_ctrl_new  = CTRL_INIT;
440	                dec_ctrl_we   = 1'b1;
441	              end
442	          end
443	
444	        CTRL_INIT:
445	          begin
446	            sword_ctr_rst = 1'b1;
447	            update_type   = INIT_UPDATE;
448	            dec_ctrl_new  = CTRL_SBOX;
449	            dec_ctrl_we   = 1'b1;
450	          end
451	
452	        CTRL_SBOX:
453	          begin
454	            sword_ctr_inc = 1'b1;
455	            update_type   = SBOX_UPDATE;
456	            if (sword_ctr_reg == 2'h3)
457	              begin
458	                round_ctr_dec = 1'b1;
459	                dec_ctrl_new  = CTRL_MAIN;
460	                dec_ctrl_we   = 1'b1;
461	              end
462	          end
463	
464	        CTRL_MAIN:
465	          begin
466	            sword_ctr_rst = 1'b1;
467	            if (round_ctr_reg > 0)
468	              begin
469	                update_type   = MAIN_UPDATE;
470	                dec_ctrl_new  = CTRL_SBOX;
471	                dec_ctrl_we   = 1'b1;
472	              end
473	            else
474	              begin
475	                update_type  = FINAL_UPDATE;
476	                ready_new    = 1'b1;
477	                ready_we     = 1'b1;
478	                dec_ctrl_new = CTRL_IDLE;
479	                dec_ctrl_we  = 1'b1;
480	              end
481	          end
482	
483	        default:
484	          begin
485	            // Empty. Just here to make the synthesis tool happy.
486	          end
487	      endcase // case (dec_ctrl_reg)
488	    end // decipher_ctrl
489	
490	endmodule // aes_decipher_block
491	
492	//======================================================================
493	// EOF aes_decipher_block.v
494	//======================================================================

