// aes_test()
//
// Main test task will perform complete NIST test of AES.
//----------------------------------------------------------------
task aes_test;
  reg [255 : 0] nist_aes128_key;
  reg [255 : 0] nist_aes256_key;

  reg [127 : 0] nist_plaintext0;
  reg [127 : 0] nist_plaintext1;
